#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

inline int maximum(int a, int b, int c) {
    int k = (b >= a) ? b : a;
    return (c >= k) ? c : k;
}

#define TEMP_IDX(y, x) ((y) * (BLOCK_SIZE + 1) + (x))
#define REF_IDX(y, x)  ((y) * BLOCK_SIZE + (x))

__kernel void nw_kernel1(__global int* reference,
                         __global int* input_itemsets,
                         __global int* output_itemsets,
                         __local int* temp,
                         __local int* ref,
                         int cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c) {
    (void)output_itemsets;
    (void)worksize;
    (void)offset_r;
    (void)offset_c;

    int bx = get_group_id(0);
    int tx = get_local_id(0);

    int b_index_x = bx;
    int b_index_y = blk - 1 - bx;

    int index    = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
    int index_n  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + 1;
    int index_w  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols;
    int index_nw = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    if (tx == 0) {
        temp[TEMP_IDX(0, 0)] = input_itemsets[index_nw];
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        ref[REF_IDX(ty, tx)] = reference[index + cols * ty];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    temp[TEMP_IDX(tx + 1, 0)] = input_itemsets[index_w + cols * tx];

    barrier(CLK_LOCAL_MEM_FENCE);

    temp[TEMP_IDX(0, tx + 1)] = input_itemsets[index_n];

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int m = 0; m < BLOCK_SIZE; m++) {
        if (m >= tx) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;

            temp[TEMP_IDX(t_index_y, t_index_x)] =
                maximum(temp[TEMP_IDX(t_index_y - 1, t_index_x - 1)] + ref[REF_IDX(t_index_y - 1, t_index_x - 1)],
                        temp[TEMP_IDX(t_index_y,     t_index_x - 1)] - penalty,
                        temp[TEMP_IDX(t_index_y - 1, t_index_x    )] - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        if (m >= tx) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;

            temp[TEMP_IDX(t_index_y, t_index_x)] =
                maximum(temp[TEMP_IDX(t_index_y - 1, t_index_x - 1)] + ref[REF_IDX(t_index_y - 1, t_index_x - 1)],
                        temp[TEMP_IDX(t_index_y,     t_index_x - 1)] - penalty,
                        temp[TEMP_IDX(t_index_y - 1, t_index_x    )] - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        input_itemsets[index + ty * cols] = temp[TEMP_IDX(ty + 1, tx + 1)];
    }
}

